### Implement Custom Tooltip in Recharts

Source: https://context7.com/recharts/recharts/llms.txt

This snippet illustrates how to create and use a custom tooltip component in Recharts. It defines a `CustomTooltip` function to render interactive tooltip content with specific styling, and then integrates it into a `LineChart` using the `Tooltip` component's `content` prop.

```jsx
import React from 'react';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';

const data = [
  { name: 'Jan', value: 4000, status: 'active' },
  { name: 'Feb', value: 3000, status: 'inactive' },
  { name: 'Mar', value: 2000, status: 'active' },
  { name: 'Apr', value: 2780, status: 'pending' },
  { name: 'May', value: 1890, status: 'active' },
];

const CustomTooltip = ({ active, payload, label }) => {
  if (active && payload && payload.length) {
    return (
      <div style={{
        backgroundColor: 'white',
        padding: '10px',
        border: '1px solid #ccc',
        borderRadius: '4px',
      }}>
        <p style={{ margin: 0, fontWeight: 'bold' }}>{`${label}`}</p>
        <p style={{ margin: '5px 0 0 0', color: payload[0].color }}>
          {`Value: ${payload[0].value}`}
        </p>
        <p style={{ margin: '5px 0 0 0', fontSize: '12px' }}>
          {`Status: ${payload[0].payload.status}`}
        </p>
      </div>
    );
  }
  return null;
};

function TooltipExample() {
  return (
    <ResponsiveContainer width="100%" height={400}>
      <LineChart data={data} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
        <XAxis dataKey="name" />
        <YAxis />

        {/* Custom tooltip with default content */}
        <Tooltip
          content={<CustomTooltip />}
          cursor={{ stroke: 'red', strokeWidth: 2 }}
          wrapperStyle={{ outline: 'none' }}
        />

        {/* Controlled tooltip */}
        <Tooltip
          active={true}
          position={{ x: 100, y: 50 }}
          filterNull={true}
        />

        <Line type="monotone" dataKey="value" stroke="#8884d8" />
      </LineChart>
    </ResponsiveContainer>
  );
}

export default TooltipExample;
```

